conditions.leftValue:
={{ 
  DateTime
    .now()
    .diff(
      DateTime.fromFormat(
        $('Get row(s) in sheet').item.json['Sequence Last Date'],
        "yyyy-MM-dd - hh:mm:ss a"
      ),
      "minutes"
    )
    .minutes
}}

